{
  "query": "query resiSearch($filters: ListingCompatabilityFilters!) { seek_listings_from_filters(filters: $filters) { total_count content { ... on Listing { listing_id listing_status primary_photo listing_page_path formatted_address(format: DOUBLE_LINE) auction {start_date end_date starting_bid } primary_property { summary { structure_type_code structure_type_group } } } } } }",
  "variables": {
    "filters": {
      "listing_type": "active",
      "usecode_property_type": "resi_sfr",
      "sort": "auction_date_order,resi_sort_v2",
      "limit": 10,
      "version": 1,
      "offset": 0
    }
  }
}

{
  "query": "query getSegments($listingIds: [ID!]!) { online_segments_batched(filters: { listing_ids: $listingIds }) { listing_id start_date initial_end_date starting_bid_amount segment_status online_segment_id } }",
  "variables": {
    "listingIds": ["2007295"]
  }
}
